package com.app.security;

import android.content.Context;
import android.security.keystore.KeyGenParameterSpec;
import android.security.keystore.KeyProperties;
import android.util.Base64;

import java.nio.ByteBuffer;
import java.nio.charset.StandardCharsets;
import java.security.KeyStore;
import java.security.SecureRandom;

import javax.crypto.Cipher;
import javax.crypto.KeyGenerator;
import javax.crypto.SecretKey;
import javax.crypto.spec.GCMParameterSpec;

public class EncryptionManager {

    private static final String ANDROID_KEYSTORE = "AndroidKeyStore";
    private static final String KEY_ALIAS_USER_PROFILE = "user_profile_key";
    private static final String KEY_ALIAS_PAYMENT_INFO = "payment_info_key";
    private static final String KEY_ALIAS_SESSION_DATA = "session_data_key";
    private static final String TRANSFORMATION = "AES/GCM/NoPadding";
    private static final int GCM_IV_LENGTH = 12;
    private static final int GCM_TAG_LENGTH = 128;

    private final KeyStore keyStore;
    private final SecureRandom secureRandom;

    public EncryptionManager() throws Exception {
        keyStore = KeyStore.getInstance(ANDROID_KEYSTORE);
        keyStore.load(null);
        secureRandom = new SecureRandom();
    }

    private void generateKeyIfNeeded(String alias) throws Exception {
        if (!keyStore.containsAlias(alias)) {
            KeyGenerator keyGenerator = KeyGenerator.getInstance(
                    KeyProperties.KEY_ALGORITHM_AES, ANDROID_KEYSTORE);

            KeyGenParameterSpec spec = new KeyGenParameterSpec.Builder(
                    alias,
                    KeyProperties.PURPOSE_ENCRYPT | KeyProperties.PURPOSE_DECRYPT)
                    .setBlockModes(KeyProperties.BLOCK_MODE_GCM)
                    .setEncryptionPaddings(KeyProperties.ENCRYPTION_PADDING_NONE)
                    .setKeySize(256)
                    .setRandomizedEncryptionRequired(false)
                    .build();

            keyGenerator.init(spec);
            keyGenerator.generateKey();
        }
    }

    private SecretKey getKey(String alias) throws Exception {
        generateKeyIfNeeded(alias);
        KeyStore.SecretKeyEntry entry = (KeyStore.SecretKeyEntry) keyStore.getEntry(alias, null);
        return entry.getSecretKey();
    }

    private String encrypt(String plaintext, String keyAlias) throws Exception {
        SecretKey key = getKey(keyAlias);

        byte[] iv = new byte[GCM_IV_LENGTH];
        secureRandom.nextBytes(iv);

        Cipher cipher = Cipher.getInstance(TRANSFORMATION);
        GCMParameterSpec gcmSpec = new GCMParameterSpec(GCM_TAG_LENGTH, iv);
        cipher.init(Cipher.ENCRYPT_MODE, key, gcmSpec);

        byte[] ciphertext = cipher.doFinal(plaintext.getBytes(StandardCharsets.UTF_8));

        ByteBuffer byteBuffer = ByteBuffer.allocate(GCM_IV_LENGTH + ciphertext.length);
        byteBuffer.put(iv);
        byteBuffer.put(ciphertext);

        return Base64.encodeToString(byteBuffer.array(), Base64.NO_WRAP);
    }

    private String decrypt(String encryptedData, String keyAlias) throws Exception {
        SecretKey key = getKey(keyAlias);

        byte[] decoded = Base64.decode(encryptedData, Base64.NO_WRAP);

        ByteBuffer byteBuffer = ByteBuffer.wrap(decoded);
        byte[] iv = new byte[GCM_IV_LENGTH];
        byteBuffer.get(iv);
        byte[] ciphertext = new byte[byteBuffer.remaining()];
        byteBuffer.get(ciphertext);

        Cipher cipher = Cipher.getInstance(TRANSFORMATION);
        GCMParameterSpec gcmSpec = new GCMParameterSpec(GCM_TAG_LENGTH, iv);
        cipher.init(Cipher.DECRYPT_MODE, key, gcmSpec);

        byte[] plaintext = cipher.doFinal(ciphertext);
        return new String(plaintext, StandardCharsets.UTF_8);
    }

    public String encryptUserProfile(String profileJson) throws Exception {
        return encrypt(profileJson, KEY_ALIAS_USER_PROFILE);
    }

    public String decryptUserProfile(String encryptedProfile) throws Exception {
        return decrypt(encryptedProfile, KEY_ALIAS_USER_PROFILE);
    }

    public String encryptPaymentInfo(String paymentJson) throws Exception {
        return encrypt(paymentJson, KEY_ALIAS_PAYMENT_INFO);
    }

    public String decryptPaymentInfo(String encryptedPayment) throws Exception {
        return decrypt(encryptedPayment, KEY_ALIAS_PAYMENT_INFO);
    }

    public String encryptSessionData(String sessionJson) throws Exception {
        return encrypt(sessionJson, KEY_ALIAS_SESSION_DATA);
    }

    public String decryptSessionData(String encryptedSession) throws Exception {
        return decrypt(encryptedSession, KEY_ALIAS_SESSION_DATA);
    }

    public void deleteAllKeys() throws Exception {
        String[] aliases = {KEY_ALIAS_USER_PROFILE, KEY_ALIAS_PAYMENT_INFO, KEY_ALIAS_SESSION_DATA};
        for (String alias : aliases) {
            if (keyStore.containsAlias(alias)) {
                keyStore.deleteEntry(alias);
            }
        }
    }
}


