// SecureDataRepository.java
package com.app.security;

import android.content.Context;

import org.json.JSONException;
import org.json.JSONObject;

public class SecureDataRepository {

    private final SecureDatabase secureDatabase;

    public SecureDataRepository(Context context) throws Exception {
        this.secureDatabase = new SecureDatabase(context);
    }

    // --- User Profile ---

    public void saveUserProfile(String userId, String name, String email, String phone)
            throws Exception {
        JSONObject profile = new JSONObject();
        profile.put("name", name);
        profile.put("email", email);
        profile.put("phone", phone);
        profile.put("timestamp", System.currentTimeMillis());
        secureDatabase.saveUserProfile(userId, profile.toString());
    }

    public JSONObject getUserProfile(String userId) throws Exception {
        String json = secureDatabase.getUserProfile(userId);
        if (json != null) {
            return new JSONObject(json);
        }
        return null;
    }

    // --- Payment Info ---

    public long savePaymentInfo(String userId, String cardNumberLastFour,
                                String cardholderName, String expiryMonth,
                                String expiryYear, String billingZip) throws Exception {
        JSONObject payment = new JSONObject();
        payment.put("card_last_four", cardNumberLastFour);
        payment.put("cardholder_name", cardholderName);
        payment.put("expiry_month", expiryMonth);
        payment.put("expiry_year", expiryYear);
        payment.put("billing_zip", billingZip);
        payment.put("timestamp", System.currentTimeMillis());
        return secureDatabase.savePaymentInfo(userId, payment.toString());
    }

    public JSONObject getPaymentInfo(long paymentId) throws Exception {
        String json = secureDatabase.getPaymentInfo(paymentId);
        if (json != null) {
            return new JSONObject(json);
        }
        return null;
    }

    public JSONObject[] getAllPaymentInfoForUser(String userId) throws Exception {
        String[] jsonArray = secureDatabase.getAllPaymentInfoForUser(userId);
        JSONObject[] results = new JSONObject[jsonArray.length];
        for (int i = 0; i < jsonArray.length; i++) {
            results[i] = new JSONObject(jsonArray[i]);
        }
        return results;
    }

    // --- Session Data ---

    public void saveSessionData(String userId, String authToken, String refreshToken,
                                long expiresAt) throws Exception {
        JSONObject session = new JSONObject();
        session.put("auth_token", authToken);
        session.put("refresh_token", refreshToken);
        session.put("expires_at", expiresAt);
        session.put("created_at", System.currentTimeMillis());
        secureDatabase.saveSessionData(userId, session.toString());
    }

    public JSONObject getSessionData(String userId) throws Exception {
        String json = secureDatabase.getSessionData(userId);
        if (json != null) {
            return new JSONObject(json);
        }
        return null;
    }

    public boolean isSessionValid(String userId) throws Exception {
        JSONObject session = getSessionData(userId);
        if (session == null) {
            return false;
        }
        long expiresAt = session.getLong("expires_at");
        return System.currentTimeMillis() < expiresAt;
    }

    // --- Cleanup ---

    public void logout(String userId) throws Exception {
        secureDatabase.deleteSessionData(userId);
    }

    public void deleteUserData(String userId) throws Exception {
        secureDatabase.deleteUserProfile(userId);
        secureDatabase.deleteAllPaymentInfoForUser(userId);
        secureDatabase.deleteSessionData(userId);
    }

    public void wipeAllData() throws Exception {
        secureDatabase.clearAllDataAndKeys();
    }

    public void close() {
        secureDatabase.close();
    }
}